const DEFAULT_LAST_VERIFIED = "2026-02-28";
const STALE_AFTER_DAYS = 45;
const PLACEHOLDER_PATTERNS = [
  /see .*fee schedule/i,
  /varies by/i,
  /processing queue/i,
  /see .*processing/i,
];

const hasPlaceholderText = (value) =>
  typeof value === "string" &&
  PLACEHOLDER_PATTERNS.some((pattern) => pattern.test(value));

const isStale = (isoDate) => {
  if (typeof isoDate !== "string") {
    return true;
  }

  const parsed = new Date(isoDate);
  if (Number.isNaN(parsed.getTime())) {
    return true;
  }

  const ageMs = Date.now() - parsed.getTime();
  const ageDays = ageMs / (1000 * 60 * 60 * 24);
  return ageDays > STALE_AFTER_DAYS;
};

export const stateData = Object.fromEntries(
  Object.entries(rawStateData).map(([stateName, record]) => {
    const hasProofPlaceholders =
      hasPlaceholderText(record.birthCertCost) ||
      hasPlaceholderText(record.birthCertTime);
    const stale = isStale(record.lastVerified ?? DEFAULT_LAST_VERIFIED);

    const derivedNeedsReview =
      hasProofPlaceholders || stale || !Array.isArray(record.verificationSourceSet);
    const needsReview =
      typeof record.needsReview === "boolean"
        ? record.needsReview
        : derivedNeedsReview;

    const confidence =
      record.confidence ??
      (hasProofPlaceholders ? "medium" : needsReview ? "low" : "high");

    return [
      stateName,
      {
        ...record,
        lastVerified: record.lastVerified ?? DEFAULT_LAST_VERIFIED,
        needsReview,
        confidence,
        verificationSourceSet: Array.isArray(record.verificationSourceSet)
          ? record.verificationSourceSet
          : [],
      },
    ];
  })
);
